125→         * the home screen with the actions and only if pressed again will it close the bottom sheet.
126→         */
127→        dialog?.setOnKeyListener { _, keyCode, event ->
128→            if (keyCode == KeyEvent.KEYCODE_BACK) {
129→                if (event.action != KeyEvent.ACTION_DOWN) {
130→                    true
131→                } else {
132→                    viewModel.onDeviceBackPressed()
