2566→    private String migrateLegacyDraft(String content) {
2567→        if (content.contains("<img src=\"null\" android-uri=\"")) {
2568→            // We must replace image tags specific to the legacy editor local drafts:
2569→            // <img src="null" android-uri="file:///..." />
2570→            // And trigger an upload action for the specific image / video
2571→            Pattern pattern = Pattern.compile("<img src=\"null\" android-uri=\"([^\"]*)\".*>");
2572→            Matcher matcher = pattern.matcher(content);
2573→            StringBuffer stringBuffer = new StringBuffer();
2574→            while (matcher.find()) {
2575→                String stringUri = matcher.group(1);
2576→                Uri uri = Uri.parse(stringUri);
2577→                MediaFile mediaFile = FluxCUtils.mediaFileFromMediaModel(mEditorMedia
2578→                        .updateMediaUploadStateBlocking(uri, MediaUploadState.FAILED));
2579→                if (mediaFile == null) {
2580→                    continue;
2581→                }
2582→                String replacement = getUploadErrorHtml(String.valueOf(mediaFile.getId()), mediaFile.getFilePath());
2583→                matcher.appendReplacement(stringBuffer, replacement);
2584→            }
2585→            matcher.appendTail(stringBuffer);
2586→            content = stringBuffer.toString();
2587→        }
2588→        if (content.contains("[caption")) {
2589→            // Convert old legacy post caption formatting to new format, to avoid being stripped by the visual editor
2590→            Pattern pattern = Pattern.compile("(\\[caption[^]]*caption=\"([^\"]*)\"[^]]*].+?)(\\[\\/caption])");
2591→            Matcher matcher = pattern.matcher(content);
2592→            StringBuffer stringBuffer = new StringBuffer();
2593→            while (matcher.find()) {
2594→                String replacement = matcher.group(1) + matcher.group(2) + matcher.group(3);
2595→                matcher.appendReplacement(stringBuffer, replacement);
2596→            }
2597→            matcher.appendTail(stringBuffer);
2598→            content = stringBuffer.toString();
2599→        }
2600→        return content;
2601→    }
