2696→    private void setPostMediaFromShareAction() {
2697→        Intent intent = getIntent();
2698→
2699→        // Check for shared media
2700→        if (intent.hasExtra(Intent.EXTRA_STREAM)) {
2701→            String action = intent.getAction();
2702→            ArrayList<Uri> sharedUris;
2703→
2704→            if (Intent.ACTION_SEND_MULTIPLE.equals(action)) {
2705→                sharedUris = intent.getParcelableArrayListExtra((Intent.EXTRA_STREAM));
2706→            } else {
2707→                // For a single media share, we only allow images and video types
2708→                if (isMediaTypeIntent(intent)) {
2709→                    sharedUris = new ArrayList<>();
2710→                    sharedUris.add(intent.getParcelableExtra(Intent.EXTRA_STREAM));
2711→                } else {
2712→                    sharedUris = null;
2713→                }
2714→            }
2715→
2716→            if (sharedUris != null) {
2717→                // removing this from the intent so it doesn't insert the media items again on each Activity re-creation
2718→                getIntent().removeExtra(Intent.EXTRA_STREAM);
2719→                mEditorMedia.addNewMediaItemsToEditorAsync(sharedUris, false);
2720→            }
2721→        }
2722→    }
